import React, { useState, useEffect } from 'react';
import { View, Text, Button, TextInput } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AuthContext = React.createContext();

const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const checkUserData = async () => {
      const userData = await AsyncStorage.getItem('userData');
      if (userData) {
        setUser(JSON.parse(userData));
      }
    };
    checkUserData();
  }, []);

  const login = async (username, authToken) => {
    const userData = { username, authToken };
    await AsyncStorage.setItem('userData', JSON.stringify(userData));
    setUser(userData);
  };

  const logout = async () => {
    await AsyncStorage.removeItem('userData');
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

const LoginScreen = () => {
  const [username, setUsername] = useState('');
  const [authToken, setAuthToken] = useState('');
  const { login } = React.useContext(AuthContext);

  return (
    <View>
      <TextInput placeholder="Username" value={username} onChangeText={setUsername} />
      <TextInput placeholder="Auth Token" value={authToken} onChangeText={setAuthToken} secureTextEntry />
      <Button title="Login" onPress={() => login(username, authToken)} />
    </View>
  );
};

const HomeScreen = () => {
  const { user, logout } = React.useContext(AuthContext);

  return (
    <View>
      <Text>Welcome, {user.username}!</Text>
      <Button title="Logout" onPress={logout} />
    </View>
  );
};

const App = () => {
  const { user } = React.useContext(AuthContext);

  return (
    <View>
      {user ? <HomeScreen /> : <LoginScreen />}
    </View>
  );
};

export default () => (
  <AuthProvider>
    <App />
  </AuthProvider>
);